<style>
        /* =========================================
           1. CORE STYLES & LAYOUT LOGIC
           ========================================= */
        :root {
            --panel-width: 280px;
            --brand-orange: #FF6A00;
            --radius-hard: 4px;
        }

        * { box-sizing: border-box; }

        body {
            margin: 0;
            padding: 0;
            font-family: 'Inter', sans-serif;
            display: flex;
            min-height: 100vh;
            background-color: #1a1a1a; 
            overflow-x: hidden;
        }

        /* --- CONTROL PANEL --- */
        #control-panel {
            width: var(--panel-width);
            background: #25262B;
            color: #eee;
            padding: 20px;
            height: 100vh;
            position: fixed;
            border-right: 1px solid #333;
            display: flex;
            flex-direction: column;
            gap: 25px;
            z-index: 1000;
            overflow-y: auto;
        }

        .panel-header {
            border-bottom: 1px solid #444;
            padding-bottom: 15px;
            display: flex;
            justify-content: space-between;
            align-items: center;
        }
        
        .panel-header strong {
            font-family: 'Oswald', sans-serif;
            letter-spacing: 1px;
            text-transform: uppercase;
        }

        .status-light {
            width: 10px;
            height: 10px;
            background-color: #8DB300;
            border-radius: 50%;
            box-shadow: 0 0 5px #8DB300;
        }

        .control-group label {
            display: block;
            font-size: 0.8rem;
            font-weight: 600;
            text-transform: uppercase;
            margin-bottom: 8px;
            color: #A6A7AB;
        }

        select {
            width: 100%;
            padding: 10px;
            background: #1A1B1E;
            border: 1px solid #444;
            color: #fff;
            cursor: pointer;
            border-radius: var(--radius-hard);
            font-family: 'Inter', sans-serif;
        }

        .btn-group {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 5px;
        }

        .layout-btn {
            padding: 10px;
            background: #1A1B1E;
            border: 1px solid #444;
            color: #ccc;
            cursor: pointer;
            font-size: 0.85rem;
            border-radius: var(--radius-hard);
            transition: 0.2s;
        }

        .layout-btn:hover, .layout-btn.active {
            background: var(--brand-orange);
            color: #000;
            font-weight: 600;
            border-color: var(--brand-orange);
        }

        .panel-footer {
            margin-top: auto;
            border-top: 1px solid #444;
            padding-top: 20px;
            font-size: 0.75rem;
            color: #666;
            text-align: center;
        }

        /* --- PREVIEW WRAPPER --- */
        #preview-wrapper {
            margin-left: var(--panel-width);
            flex-grow: 1;
            background: var(--bg-color, #fff);
            color: var(--text-color, #333);
            transition: background 0.3s ease;
            min-height: 100vh;
            display: flex;
            flex-direction: column;
        }

        /* --- MOCK HEADER/FOOTER --- */
        .mock-global-header, .mock-global-footer {
            padding: 20px;
            border-top: 5px solid var(--accent-color, #ccc);
            border-bottom: 1px solid #ddd;
            background: var(--surface-color, #f9f9f9);
            display: flex;
            justify-content: space-between;
            align-items: center;
        }

        .mock-global-footer {
            margin-top: auto;
            border-top: 1px solid #ddd;
            border-bottom: 5px solid var(--accent-color, #ccc);
        }
        
        .mock-global-header nav span { margin-left: 15px; cursor: pointer; text-decoration: underline;}
        .cta-mock { 
             background: var(--accent-color); 
             color: #fff; 
             padding: 8px 15px; 
             text-decoration: none !important;
             border-radius: var(--radius-hard);
        }

        /* --- WIREFRAME COMPONENTS --- */
        .wf-section {
            padding: 40px;
            border-bottom: 1px dashed var(--border-color, #ccc);
        }

        .wf-hero {
            min-height: 300px;
            background: var(--surface-color, #eee);
            display: flex;
            align-items: center;
            justify-content: center;
            text-align: center;
            flex-direction: column;
        }

        .wf-box {
            background: var(--surface-color, #eee);
            border: 1px solid var(--border-color, #999);
            padding: 20px;
            margin-bottom: 10px;
            min-height: 150px;
            border-radius: var(--radius-hard);
        }

        .wf-img-placeholder {
            width: 100%;
            height: 200px;
            background: #ccc;
            display: flex;
            align-items: center;
            justify-content: center;
            color: #666;
            margin-bottom: 15px;
            border: 1px dashed #999;
            border-radius: var(--radius-hard);
        }

        button.wf-btn {
            padding: 12px 24px;
            background: var(--accent-color);
            color: #fff;
            border: none;
            cursor: pointer;
            margin-top: 15px;
            border-radius: var(--radius-hard);
            font-size: 1rem;
        }

        /* --- LAYOUT SYSTEMS --- */
        .layout-stack .grid-container { display: block; }
        .layout-stack .wf-box { margin-bottom: 20px; }

        .layout-split .wf-hero { flex-direction: row; text-align: left; gap: 40px; padding: 60px 40px; }
        .layout-split .grid-container { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }

        .layout-grid .grid-container { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }
        .layout-grid .wf-hero { min-height: 400px; }

        .layout-sidebar .page-wrapper { display: grid; grid-template-columns: 3fr 1fr; gap: 30px; padding: 20px; }
        .layout-sidebar .wf-hero { grid-column: 1 / -1; }
        
        @media (max-width: 768px) {
            .layout-sidebar .page-wrapper { grid-template-columns: 1fr; }
            .layout-grid .grid-container { grid-template-columns: 1fr; }
            .layout-split .grid-container { grid-template-columns: 1fr; }
            .layout-split .wf-hero { flex-direction: column; text-align: center; gap: 20px;}
            :root { --panel-width: 0px; }
            #control-panel { transform: translateX(-100%); transition: 0.3s; }
            #control-panel.mobile-open { transform: translateX(0); width: 280px; }
        }

        /* =========================================
           CSNZ SERVICES FOOTER
           ========================================= */
        .csnz-services-list {
            margin-left: 0; 
            background: #121212; 
            color: #eee;
            padding: 60px 40px;
            width: 100%;
            border-top: 1px solid #333;
        }

        .csnz-services-list h3 {
            text-transform: uppercase;
            letter-spacing: 1px;
            border-bottom: 1px solid #333;
            padding-bottom: 15px;
            margin-bottom: 40px;
            font-size: 1.2rem;
            color: #fff;
            text-align: center;
        }

        .services-grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
            gap: 30px;
            max-width: 1200px;
            margin: 0 auto;
        }

        .service-card {
            background: #1A1A1A;
            border: 1px solid #333;
            display: flex;
            flex-direction: column;
            transition: all 0.2s ease;
            border-radius: var(--radius-hard);
            overflow: hidden;
        }

        .service-card:hover {
            border-color: var(--brand-orange);
            transform: translateY(-3px);
        }

        .card-visual {
            width: 100%;
            height: 180px;
            overflow: hidden;
            border-bottom: 1px solid #333;
        }
        
        .card-visual img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            opacity: 0.9;
            transition: 0.3s ease;
        }

        .service-card:hover .card-visual img {
            opacity: 1;
            transform: scale(1.02);
        }

        .card-body {
            padding: 25px;
            flex-grow: 1;
            display: flex;
            flex-direction: column;
        }

        .service-card strong {
            font-size: 1.25rem;
            text-transform: uppercase;
            color: #fff;
            margin-bottom: 10px;
            display: block;
            font-family: 'Oswald', sans-serif;
        }

        .card-desc {
            font-size: 0.9rem;
            color: #A6A7AB;
            line-height: 1.5;
            margin-bottom: 20px;
            flex-grow: 1;
        }

        .btn-service {
            display: block;
            width: 100%;
            text-align: center;
            background: var(--brand-orange);
            color: #000;
            padding: 12px 0;
            text-transform: uppercase;
            font-weight: bold;
            text-decoration: none;
            font-size: 0.9rem;
            border-radius: 4px;
            transition: 0.2s;
        }

        .btn-service:hover {
            filter: brightness(110%);
        }

        /* =========================================
           2. THEME DEFINITIONS
           ========================================= */
        .theme-blueprint {
            --bg-color: #ffffff;
            --text-color: #333333;
            --surface-color: #f0f4f8;
            --border-color: #b0c4de; 
            --accent-color: #0056b3;
            --font-main: 'Inter', sans-serif;
        }

        .theme-bold {
            --bg-color: #ffffff;
            --text-color: #000000;
            --surface-color: #eeeeee;
            --border-color: #000000;
            --accent-color: #FF6A00;
            --font-main: 'Oswald', sans-serif;
        }
        .theme-bold .wf-section { border-bottom: 2px solid black; }
        .theme-bold .wf-box { border: 2px solid black; border-radius: 0; }
        .theme-bold button.wf-btn { color: #000; border-radius: 0; font-weight: bold; }

        .theme-clean {
            --bg-color: #fcfcfc;
            --text-color: #444444;
            --surface-color: #ffffff;
            --border-color: #e5e5e5;
            --accent-color: #27ae60;
            --font-main: 'Inter', sans-serif;
        }
        .theme-clean .wf-box { border: 1px solid #eee; box-shadow: 0 4px 10px rgba(0,0,0,0.05); }
        .theme-clean .wf-section { border: none; }

        .theme-dark {
            --bg-color: #121212;
            --text-color: #e0e0e0;
            --surface-color: #1e1e1e;
            --border-color: #333333;
            --accent-color: #bb86fc;
            --font-main: 'Inter', sans-serif;
        }
        .theme-dark .wf-img-placeholder { background: #333; color: #fff; border-color: #555;}
        .theme-dark .mock-global-header, .theme-dark .mock-global-footer { background: #1e1e1e; border-color: #333; color: #fff; }
        .theme-dark .wf-box { background: #1e1e1e; border-color: #333; }

        #preview-wrapper { font-family: var(--font-main); }
    </style>
</head>
<body>
    <div id="control-panel">
        <div class="panel-header">
            <strong>Layout Viewer</strong>
            <span class="status-light"></span>
